// Webhook body carries { application_id }. design.md SS8: 05's rollup scores the
// APPLICATION, not the founder -- 03 already owns founder_id-keyed scores.
const item = $input.first().json;
const body = item.body || {};
const application_id = body.application_id || item.application_id;
if (!application_id) throw new Error('f05-trust-rollup: application_id is required');
return [{ json: { application_id } }];

// Called by 06/09/10 as a sub-workflow with { application_id }.
const item = $input.first().json || {};
const application_id = item.application_id;
if (!application_id) throw new Error('f05-trust-rollup: application_id is required');
return [{ json: { application_id } }];

// One UUID per rollup run -- echoed into the trust_rollup_insufficient_evidence
// event's payload when the coverage gate fails (lib/f05/trust.js's ctx.runId,
// design.md SS8.2). globalThis.crypto is undefined inside this n8n build's actual
// Code-node VM sandbox (verified live 2026-07-19 -- a plain `docker exec node -e`
// process exposes it, the task-runner's sandbox does not), so require('crypto') is
// used instead -- allow-listed in infra/n8n/docker-compose.yml
// (NODE_FUNCTION_ALLOW_BUILTIN=crypto,url), same proven pattern as f03's own
// gen_run_id node.
const { randomUUID } = require('crypto');
const inp = $input.first().json;
return [{ json: { application_id: inp.application_id, run_id: randomUUID() } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const rows = await pgGet.call(this,
  'applications?id=eq.' + inp.application_id + '&select=id,company_id');
if (!rows || !rows.length) {
  throw new Error('f05-trust-rollup: no application found for id ' + inp.application_id);
}
return [{ json: { ...inp, company_id: rows[0].company_id } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS8.1 route 3's founderIds -- "resolved by the caller with a
// single-table lookup, not re-derived" inside trust.js (lib/f05/trust.js's own file
// header contract).
const rows = await pgGet.call(this,
  'founder_company?company_id=eq.' + inp.company_id + '&select=founder_id');
const founder_ids = (rows || []).map(function (r) { return r.founder_id; }).filter(Boolean);
return [{ json: { ...inp, founder_ids } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const rows = await pgGet.call(this,
  'score_formulas?axis=eq.trust&active=eq.true&select=version,config&limit=1');
if (!rows || !rows.length) {
  throw new Error("f05-trust-rollup: no active score_formulas row for axis='trust'");
}
// lib/f05/trust.js's own config shape -- { version, min_coverage } (SS7.5/SS8.2's
// LEFT JOIN + literal-fallback discipline: read the live row here rather than a
// second hardcoded copy; computeTrustRollup applies its OWN literal fallback if
// config.rollup is entirely absent, e.g. a fresh clone before seed.sql has run).
const rollup_cfg = rows[0].config && rows[0].config.rollup;
const rollup_config = { version: rows[0].version, min_coverage: rollup_cfg && rollup_cfg.min_coverage };
return [{ json: { ...inp, rollup_config } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS8.1 -- the same three OR'd routes lib/f05/trust.js's own
// isClaimInScope() applies in JS, expressed here as a PostgREST 'or' filter over
// `cards`. claim_trust is a VIEW with no FK metadata PostgREST can embed through, so
// the join happens as two round trips -- cards first (this node), then claim_trust
// filtered by card_id (next node), merged back together there. This query is the
// UNRESTRICTED superset (route 3 with no company_id restriction) -- lib/f05/trust.js's
// own scopeClaimsToApplication() applies that restriction inside the ROLLUP node
// below, exactly as its file header documents ("a caller may pass a superset and
// rely on this module for the restriction").
const orParts = [
  'application_id.eq.' + inp.application_id,
  'company_id.eq.' + inp.company_id,
];
if (inp.founder_ids && inp.founder_ids.length) {
  orParts.push('founder_id.in.(' + inp.founder_ids.join(',') + ')');
}
const cards = await pgGet.call(this,
  'cards?select=id,application_id,company_id,founder_id&or=(' + orParts.join(',') + ')');
return [{ json: { ...inp, scope_cards: cards || [] } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const cardIds = (inp.scope_cards || []).map(function (c) { return c.id; });
let claimRows = [];
if (cardIds.length) {
  claimRows = await pgGet.call(this,
    'claim_trust?select=claim_id,card_id,topic,router_class,derived_status,trust,' +
    'independence_factor,n_supports,n_contradicts&card_id=in.(' + cardIds.join(',') + ')');
}

// Column-contract reconciliation (lib/f05/run.js's own term for this same step):
// claim_trust exposes only card_id, not the three card FKs lib/f05/trust.js's row
// shape needs (card_application_id/card_company_id/card_founder_id) -- merged in here
// from the cards rows fetched by the previous node, keyed by card_id.
const cardsById = new Map((inp.scope_cards || []).map(function (c) { return [c.id, c]; }));
const rows = (claimRows || []).map(function (r) {
  const card = cardsById.get(r.card_id) || {};
  return {
    claim_id: r.claim_id,
    topic: r.topic,
    class: r.router_class,
    derived_status: r.derived_status,
    trust: r.trust,
    independence_factor: r.independence_factor,
    n_supports: r.n_supports,
    n_contradicts: r.n_contradicts,
    card_application_id: card.application_id || null,
    card_company_id: card.company_id || null,
    card_founder_id: card.founder_id || null,
  };
});
return [{ json: { ...inp, rows } }];

