  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await this.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}
const inp = $input.first().json;
// design.md SS8.2/SS8.3 -- no idempotency guard by design ("accept duplicates under
// append-only semantics... resolve current by max(computed_at)"), matching scores'
// own project-wide write convention (e.g. lib/f03/run.js's writeScored).
const sr = inp.rollup.scoresRow;
const rows = await pg.call(this, 'POST', 'scores', {
  application_id: sr.application_id,
  founder_id: null,
  axis: 'trust',
  value: sr.value,
  confidence: sr.confidence,
  missing_flags: sr.missing_flags,
  input_claim_ids: sr.input_claim_ids,
  formula_version: sr.formula_version,
